#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int superheroes = 1;
        int villains = 1;
        for (int i = 0; i < N; i++) {
            char name[16];
            scanf("%s", name);
            if (strcmp(name + strlen(name) - 3, "man") == 0 || strcmp(name + strlen(name) - 5, "woman") == 0) {
                superheroes++;
            } else {
                villains++;
            }
            if (superheroes - villains == 2) {
                printf("superheroes\n");
                break;
            } else if (villains - superheroes == 3) {
                printf("villains\n");
                break;
            }
        }
        if (superheroes - villains != 2 && villains - superheroes != 3) {
            printf("draw\n");
        }
    }
    return 0;
}

