        while (T-- > 0) {
            int N = scanner.nextInt();
            int superheroes = 1;
            int villains = 1;
            for (int i = 0; i < N; i++) {
                String name = scanner.next();
                if (name.endsWith("man") || name.endsWith("woman")) {
                    superheroes++;
                } else {
                    villains++;
                }
                if (superheroes - villains == 2) {
                    System.out.println("superheroes");
                    break;
